def evaluate(exp):
    if isinstance(exp, int):
        return exp
    operator = exp[0]
    values = []
    for operand in exp[1:]:
        values.append(evaluate(operand))
    return apply_operator(operator, values)


def apply_operator(operator, values):
    if operator == "+":
        return values[0] + values[1]
    if operator == "*":
        return values[0] * values[1]
    raise ValueError(operator)


program = ["*", ["+", 1, 2], ["+", 2, 3]]
result = evaluate(program)
